  `usage_this_month` decimal(10,2) NOT NULL DEFAULT '0.00',
  `usage_trend_pct` decimal(5,2) DEFAULT NULL,
  `status` enum('active','paused','emergency','suspended') COLLATE utf8mb4_general_ci DEFAULT 'active',
  `last_checked_at` datetime DEFAULT NULL,
  `last_check_error` text COLLATE utf8mb4_general_ci,
  `checked_by` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

