(1, 'Climate Resilience in African Agriculture', 'International Climate Action Fund', '2026-08-31', 'open', 'Support innovative climate adaptation strategies in smallholder farming systems across Sub-Saharan Africa. Focus on drought-resistant crops, water harvesting, and farmer-led innovation.', 'climate,agriculture,resilience,adaptation', 'africa,sub-saharan africa', '$500,000 - $2,000,000', 'https://climateactionfund.org/grants/africa', 'globalclimate@testfunder.org', '2026-05-19 23:36:08', '2026-05-29 23:58:37', '2026-05-29 23:58:37', 'factalliance@mit.edu'),
(2, 'Water Governance in the Middle East', 'World Water Council', '2026-09-15', 'rolling', 'Fund research and policy solutions for transboundary water management and governance in shared river basins. Priority regions: Jordan River, Tigris-Euphrates, Nile.', 'water,governance,policy', 'middle east,africa', '$250,000 - $1,500,000', 'https://watergov.org/mena', 'waterinnovation@testfunder.org', '2026-05-19 23:36:09', '2026-05-22 15:11:59', '2026-05-22 15:11:59', 'factalliance@mit.edu'),
(3, 'Sustainable Food Systems Innovation', 'Global Food Security Initiative', '2026-07-30', 'open', 'Support transformative innovations in food production, processing, and distribution to enhance food security and nutrition in developing countries.', 'food security,agriculture,nutrition,innovation', 'global,africa,asia,americas', '$1,000,000 - $5,000,000', 'https://foodsecurity.org/innovation', 'foodfuture@testfunder.org', '2026-05-19 23:36:09', '2026-05-28 17:05:38', '2026-05-28 17:05:38', 'factalliance@mit.edu'),
(4, 'Malaria Elimination Research', 'Disease Control International', '2026-10-31', 'rolling', 'Fund cutting-edge research on malaria vector control, drug resistance, and novel diagnostic tools to accelerate malaria elimination.', 'malaria,health,disease,research', 'africa,asia', '$400,000 - $3,000,000', 'https://diseasecontrol.org/malaria', 'healthworldwide@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:58:46', '2026-05-29 23:58:46', 'factalliance@mit.edu'),
(5, 'Women Entrepreneurs in Agriculture', 'Women in Development Fund', '2026-06-30', 'closed', 'Support women-led agricultural enterprises and agribusiness startups in low-income countries. Includes training, mentoring, and market access.', 'gender,women,agriculture,economic development', 'africa,asia,latin america', '$100,000 - $500,000', 'https://womenindev.org/agriculture', 'genderempowerment@testfunder.org', '2026-05-19 23:36:09', '2026-05-22 15:09:42', '2026-05-22 15:09:42', 'factalliance@mit.edu'),
(6, 'Rural Renewable Energy Access', 'Sustainable Energy for All', '2026-09-30', 'open', 'Scale up solar, wind, and hydropower solutions to provide reliable, affordable energy to remote and underserved communities.', 'energy,innovation,poverty,sustainability', 'africa,asia,americas', '$300,000 - $2,500,000', 'https://sustainableenergy.org/rural', 'energyaccess@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:58:50', '2026-05-29 23:58:50', 'factalliance@mit.edu'),
(7, 'Biodiversity Conservation in Tropical Forests', 'Nature Conservation Alliance', '2026-11-15', 'rolling', 'Protect tropical forest ecosystems and their biodiversity through community-based conservation and sustainable land-use practices.', 'biodiversity,environment,conservation', 'americas,asia,africa', '$500,000 - $3,000,000', 'https://naturealliance.org/forests', 'biodiversity@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:58:54', '2026-05-29 23:58:54', 'factalliance@mit.edu'),
(8, 'Quality Education for Marginalized Communities', 'Learning Futures Foundation', '2026-08-15', 'open', 'Improve educational quality and access for children in rural, conflict-affected, and marginalized communities through innovative teaching methods.', 'education,poverty,capacity building', 'asia,africa,americas', '$250,000 - $1,500,000', 'https://learningfutures.org/education', 'education@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:58:58', '2026-05-29 23:58:58', 'factalliance@mit.edu'),
(9, 'Agricultural Trade and Market Development', 'Emerging Market Trade Initiative', '2026-12-31', 'rolling', 'Strengthen agricultural value chains and market linkages for smallholder farmers in emerging economies to increase income and reduce poverty.', 'agriculture,economic development,trade', 'asia,africa,americas', '$350,000 - $2,000,000', 'https://emergingtrade.org/agriculture', 'tradegrowth@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:59:16', '2026-05-29 23:59:16', 'factalliance@mit.edu'),
(10, 'Disaster Risk Reduction and Resilience', 'Disaster Risk Reduction Fund', '2026-09-30', 'open', 'Build community resilience to climate-related hazards and natural disasters through early warning systems, adaptation planning, and disaster preparedness.', 'climate,resilience,disaster management,adaptation', 'global,asia,americas,africa', '$200,000 - $1,200,000', 'https://drrfund.org/resilience', 'resilience@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:59:03', '2026-05-29 23:59:03', 'factalliance@mit.edu'),
(11, 'Transformative Research on Food Systems', 'International Science Foundation', '2026-10-31', 'open', 'Fund high-impact research addressing fundamental challenges in global food security, nutrition, and sustainable agriculture.', 'innovation,research,sustainability,food security', 'global', '$600,000 - $3,500,000', 'https://sciencefoundation.org/food', 'research@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:59:07', '2026-05-29 23:59:07', 'factalliance@mit.edu'),
(12, 'Digital Innovation for Development', 'Technology for Development Programme', '2026-09-15', 'rolling', 'Scale digital and technology solutions to improve agricultural productivity, financial inclusion, and service delivery in developing countries.', 'innovation,technology,ict,economic development', 'africa,asia,americas', '$150,000 - $1,000,000', 'https://techdev.org/innovation', 'innovation@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:59:12', '2026-05-29 23:59:12', 'factalliance@mit.edu'),
(13, 'Water-Energy-Food Nexus Research', 'World Water Council', '2026-11-30', 'open', 'Advance integrated approaches to managing the interconnections between water, energy, and food security.', 'water,energy,food security,innovation', 'asia,middle east,americas', '$400,000 - $2,500,000', 'https://watergov.org/nexus', 'waterinnovation@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:59:21', '2026-05-29 23:59:21', 'factalliance@mit.edu'),
(14, 'Climate-Smart Agriculture Initiative', 'International Climate Action Fund', '2026-07-31', 'open', 'Implement and evaluate climate-smart agricultural practices that increase productivity while adapting to climate change.', 'climate,agriculture,innovation,adaptation', 'africa,asia,americas', '$600,000 - $3,000,000', 'https://climateactionfund.org/csa', 'globalclimate@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:59:25', '2026-05-29 23:59:25', 'factalliance@mit.edu'),
(15, 'Nutrition Security Program', 'Global Food Security Initiative', '2026-08-31', 'rolling', 'Combat malnutrition through multi-sectoral approaches including agriculture, health, education, and water and sanitation.', 'nutrition,food security,health,poverty', 'africa,asia', '$300,000 - $2,000,000', 'https://foodsecurity.org/nutrition', 'foodfuture@testfunder.org', '2026-05-19 23:36:09', '2026-05-29 23:59:29', '2026-05-29 23:59:29', 'factalliance@mit.edu'),
(16, 'AFRI Foundational and Applied Science (FAS) Program', 'USDA National Institute of Food and Agriculture (NIFA)', '2026-12-31', 'rolling', 'The flagship USDA competitive agricultural research grant program, supporting both fundamental and applied sciences across six priority areas: (1) Plant Health and Production and Plant Products; (2) Animal Health and Production and Animal Products; (3) Food Safety, Nutrition, and Health; (4) Bioenergy, Natural Resources, and Environment; (5) Agriculture Systems and Technology; and (6) Agriculture Economics and Rural Communities. Research-only, extension-only, and integrated research, education and/or extension projects are all eligible. Deadlines vary by priority area — applicants should consult the full NOFO.', 'Food safety; Nutrition and health; Bioenergy; Natural resources; Environment; Agricultural systems; Technology; Agricultural economics; Rural communities; Plant health; Animal health', 'USA (international collaboration permitted where relevant)', '$10,000 – $10,000,000 per award; Estimated total program funding: $300,000,000', 'https://www.nifa.usda.gov/grants/funding-opportunities/agriculture-food-research-initiative-foundational-applied-science', 'factalliance@mit.edu', '2026-06-01 18:44:24', '2026-06-01 18:48:32', '2026-06-01 18:48:32', 'factalliance@mit.edu'),
(17, 'AFRI Foundational and Applied Science (FAS) Program', 'USDA National Institute of Food and Agriculture (NIFA)', '2026-12-31', 'rolling', 'The flagship USDA competitive agricultural research grant program, supporting both fundamental and applied sciences across six priority areas: (1) Plant Health and Production and Plant Products; (2) Animal Health and Production and Animal Products; (3) Food Safety, Nutrition, and Health; (4) Bioenergy, Natural Resources, and Environment; (5) Agriculture Systems and Technology; and (6) Agriculture Economics and Rural Communities. Research-only, extension-only, and integrated research, education and/or extension projects are all eligible. Deadlines vary by priority area — applicants should consult the full NOFO.', 'Food safety; Nutrition and health; Bioenergy; Natural resources; Environment; Agricultural systems; Technology; Agricultural economics; Rural communities; Plant health; Animal health', 'USA (international collaboration permitted where relevant)', '$10,000 – $10,000,000 per award; Estimated total program funding: $300,000,000', 'https://www.nifa.usda.gov/grants/funding-opportunities/agriculture-food-research-initiative-foundational-applied-science', 'factalliance@mit.edu', '2026-06-01 18:49:43', '2026-06-01 18:49:43', NULL, NULL),
(18, 'Open Data Framework (ODF)', 'USDA National Institute of Food and Agriculture (NIFA)', '2026-06-26', 'open', 'Builds frameworks to create neutral and secure data repositories and cooperatives where producers, universities and nonprofit entities can store and share agricultural data to foster innovation, support technological progress, profitability, and production efficiency. Priority areas include: farm and ranch profitability; new markets and uses for agricultural products; invasive species; soil health to regenerate long-term productivity; and improving human health through precision nutrient and food quality. Eligible applicants include State agricultural experiment stations, colleges and universities, research institutions, Federal agencies, national laboratories, private organizations and foundations, corporations, and individuals.', 'Agricultural data repositories; Data sharing; Soil health; Farm profitability; Market innovation; Precision nutrition; Food quality; Invasive species; Technology infrastructure', 'USA', '$923,325 (single award)', 'https://www.nifa.usda.gov/grants/funding-opportunities/open-data-framework', 'factalliance@mit.edu', '2026-06-01 18:53:26', '2026-06-01 18:53:26', NULL, NULL),
(19, 'Rapid Outcomes from Agricultural Research (ROAR)', 'Foundation for Food & Agriculture Research (FFAR)', '2026-12-31', 'rolling', 'Deploys urgent funding to combat emerging or unanticipated pests and pathogens threatening the U.S. food supply or agricultural systems. Funds rapid research on diagnostics, monitoring and mitigation strategies. Applicants submit a one-page concept note; if accepted, a full application is due within 8 weeks. Eligible threats must be of regional or national significance. Can also fund pre-outbreak preparedness and diagnostic tool development.', 'Food system resilience; Crop and livestock pests and pathogens; Disease diagnostics; Food supply security; Biosecurity; Outbreak preparedness; Emerging threats', 'USA (international eligible if direct and significant U.S. threat)', 'Up to $250,000 per grant (1–2 years)', 'https://foundationfar.org/programs/rapid-outcomes-from-agricultural-research/', 'factalliance@mit.edu', '2026-06-01 19:00:48', '2026-06-01 19:03:35', NULL, NULL),
(20, 'Letters of Inquiry (LOI) — Environmental Justice Program (Venture, Advancement & Enterprise Grants)', 'Nathan Cummings Foundation (NCF)', '2026-12-31', 'rolling', 'NCF welcomes Letters of Inquiry year-round through its online portal for organizations aligned with Racial, Economic, and Environmental Justice (REEJ). The Environmental Justice program focuses on three 2026 priority areas, with emphasis on work in or focused on the U.S. South: (1) Environmental Harms — providing frontline BIPOC and low-income communities with actionable data, long-term protective solutions, and holding polluters accountable; (2) Inclusive Participation in the Green Economy — measurably increasing jobs, investments, and wealth-building in the clean energy transition for marginalized communities; and (3) Regenerative Economic Models — transitioning or restoring agricultural, forest or watershed lands; scaling innovative alternatives to extractive industries; and demonstrating regenerative economic models. Program-Related Investments (PRIs) are also available ($250K–$750K, typically repaid within 3–7 years). Note: NCF does not fund conservation projects, direct service programs, or community gardening/tree planting as standalone activities.', 'Environmental justice; Regenerative agriculture and land restoration; Watershed restoration; Green economy transition; Climate adaptation; Frontline community data and advocacy; Alternatives to extractive industries; Pollution accountability', 'USA — 40% of assets focused on the U.S. South', 'Venture Grants: up to $100,000 (1 year) | Advancement Grants: up to $250,000/year (up to 2 years) |', 'https://nathancummings.org/become-a-partner/', 'factalliance@mit.edu', '2026-06-05 18:59:46', '2026-06-05 19:00:56', NULL, NULL),
(21, 'Sustainable Development Program — Thematic Grant Inquiry', 'Rockefeller Brothers Fund (RBF)', '2026-12-31', 'rolling', 'The RBF Sustainable Development program funds charitable organizations working to combat climate change, with a primary focus on effective U.S. climate policy at federal, state, and local levels, and selected international efforts on global climate negotiations.', 'Climate change policy; Clean energy economy; Green economy transition; Carbon reduction; International climate negotiations; U.S. federal, state, and local climate policy; Climate communications.', 'Usa & International(Central America: El Salvador, Guatemala, Honduras, China, Western Balkans: Albania, Bosnia, Kosovo, Montenegro, North Macedonia)', '25,000 – $300,000 per grant. Typical grant range based on historical awards. No capital expenses;', 'https://www.rbf.org/grants/for-grant-seekers', 'factalliance@mit.edu', '2026-06-05 19:09:13', '2026-06-05 19:36:05', NULL, NULL),
(22, 'NSF SBIR/STTR Phase I — Agricultural Technologies (AG) Topic', 'National Science Foundation (NSF) — America\'s Seed Fund (SBIR/STTR Program, Solicitation NSF 26-510)', '2026-11-04', 'open', 'NSF\'s flagship non-dilutive seed funding program for US small businesses (under 500 employees) developing high-risk, high-impact deep technologies with strong commercial potential. The Agricultural Technologies (AG) topic specifically funds innovations enabling farm production ecosystems that support the proper utilization of natural resources, including systems-level and multidisciplinary solutions.', 'Agroforestry; food waste; precision agriculture; polyculture; nature-based solutions; agricultural & supply chain resilience; farm access; systems ecology.', 'Usa Only — All Funded Work (Including Consultants And Contractors) Must Take Place In The United States', 'Phase I: up to $305K (6–12 months); Phase II: $1.25M–$1.8M (24 months); Fast-Track: $1.56M–$2.', 'https://seedfund.nsf.gov/topics/agricultural-technologies/', 'factalliance@mit.edu', '2026-06-11 15:48:18', '2026-06-11 15:48:18', NULL, NULL),
(23, 'NSF SBIR/STTR — Environmental Technologies (ET), incl. Sub-topic ET4: Food, Regenerative Agriculture & Energy.', 'National Science Foundation (NSF) — America\'s Seed Fund (SBIR/STTR Program, Solicitation NSF 26-510)', '2026-11-04', 'open', 'NSF ET funds environmental innovations in sensing, analytics, sustainability, food systems, resilience, circular economy, and water solutions. Relevant areas include ET1, ET2, ET3, ET4, ET6–ET8, with ET4 directly aligning with regenerative agriculture and food systems. Focus: innovation, broader impact, and commercial potential.', 'Regenerative agriculture; food systems; environmental data; conservation; circular economy; waste reduction; water resilience; climate adaptation; sustainable systems.', 'Usa Only — All Funded Work Must Take Place In The United States', 'Phase I: up to $305K; Phase II: $1.25M–$1.8M; Fast-Track: up to $2.1M. No equity taken.', 'https://seedfund.nsf.gov/topics/agricultural-technologies/', 'factalliance@mit.edu', '2026-06-11 16:01:23', '2026-06-11 16:01:23', NULL, NULL);

