--
-- Table structure for table `funding_call_embeddings`
--

CREATE TABLE `funding_call_embeddings` (
  `id` int NOT NULL,
  `funding_call_id` int NOT NULL,
  `embedding_type` varchar(50) NOT NULL COMMENT 'full, title, description',
  `embedding` longtext NOT NULL COMMENT 'JSON array of floats (1536-dim)',
  `content_hash` varchar(64) NOT NULL COMMENT 'SHA256 of source content',
  `model_used` varchar(100) DEFAULT 'claude-embeddings-v3.5',
  `generated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- --------------------------------------------------------

--
-- Table structure for table `job_queue`
--

CREATE TABLE `job_queue` (
  `id` int NOT NULL,
  `job_type` enum('compute_matches','generate_summary','send_notification','send_digest','check_balance','fetch_orcid_publications','send_weekly_digests','generate_embedding') COLLATE utf8mb4_general_ci NOT NULL,
  `payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `status` enum('pending','processing','completed','failed') COLLATE utf8mb4_general_ci DEFAULT 'pending',
  `attempts` tinyint UNSIGNED NOT NULL DEFAULT '0',
  `max_attempts` tinyint UNSIGNED NOT NULL DEFAULT '3',
  `last_error` text COLLATE utf8mb4_general_ci,
  `locked_at` datetime DEFAULT NULL,
  `locked_by` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `run_after` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `idempotency_key` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL
) ;

