--
-- Table structure for table `match_scores`
--

CREATE TABLE `match_scores` (
  `id` int NOT NULL,
  `funding_call_id` int NOT NULL,
  `researcher_id` int NOT NULL,
  `score_keyword` tinyint UNSIGNED NOT NULL DEFAULT '0',
  `score_ai` tinyint UNSIGNED DEFAULT NULL,
  `explanation` text COLLATE utf8mb4_general_ci,
  `model_used` varchar(80) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `computed_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `notified_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `match_scores`
--

INSERT INTO `match_scores` (`id`, `funding_call_id`, `researcher_id`, `score_keyword`, `score_ai`, `explanation`, `model_used`, `computed_at`, `notified_at`) VALUES
(1, 3, 41, 3, 72, 'Strong alignment on food security and food systems innovation with geographic overlap in Asia, but limited evidence of specific expertise in agriculture, nutrition, processing/distribution, or developing country context beyond the bio statement.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:45', '2026-05-19 23:44:11'),
(2, 3, 42, 1, 72, 'Strong alignment on agricultural innovation systems and global/African geography, but researcher\'s qualitative social science and water governance focus diverges from the call\'s emphasis on food production, processing, distribution innovation and nutrition outcomes.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:47', '2026-05-19 23:44:12'),
(3, 3, 43, 3, 72, 'Strong alignment on food security and tech food systems innovation in Asia, but limited by student status without demonstrated research track record, and narrow geographic focus compared to the global/multi-regional scope sought by the funder.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:48', '2026-05-19 23:44:12'),
(4, 3, 44, 4, 78, 'Strong alignment on agriculture and food security topics with relevant geographic focus in South America, but lacks explicit mention of nutrition, innovation, processing/distribution systems, and presence in other priority regions like Africa and Asia.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:50', '2026-05-19 23:44:12'),
(5, 3, 45, 1, 15, 'Minimal alignment: while the researcher is Africa-based which matches geography, their focus on water and governance topics does not align with the funding call\'s priorities of food production, processing, distribution, nutrition, and innovation in sustainable food systems.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:51', NULL),
(6, 3, 46, 1, 15, 'Minimal alignment: researcher\'s focus on water and energy sustainability has tangential relevance to food systems, but lacks expertise in agriculture, food production, nutrition, and food security that are central to this funding call.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:53', NULL),
(7, 3, 47, 1, 5, 'Researcher\'s expertise in malaria and disease control has minimal overlap with the funding call\'s focus on food systems, agriculture, and nutrition innovation, with only geographic alignment in Africa.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:54', NULL),
(8, 3, 48, 0, 15, 'Minimal alignment: while climate and biodiversity topics tangentially relate to sustainable food systems, the researcher\'s geographic focus (Europe, Russia, Arctic) and expertise areas (climate, environment, biodiversity) do not directly address the call\'s priorities of food security, agriculture, nutrition, or innovation in developing countries across Africa, Asia, and Americas.', 'claude-haiku-4-5-20251001', '2026-05-19 23:43:58', NULL),
(9, 3, 49, 3, 58, 'Strong geographic alignment (Americas, Mexico) and innovation focus, but researcher\'s emphasis on environment and biodiversity lacks direct connection to the funding call\'s core priorities of food security, agriculture, and nutrition.', 'claude-haiku-4-5-20251001', '2026-05-19 23:44:00', NULL),
(10, 3, 50, 3, 72, 'Strong geographic alignment (Africa/West Africa) and agriculture topic overlap, but researcher\'s focus on gender and economic development rather than food security, nutrition, or innovation represents a meaningful gap in thematic priorities.', 'claude-haiku-4-5-20251001', '2026-05-19 23:44:04', '2026-05-19 23:44:12'),
(11, 3, 51, 5, 78, 'Strong alignment on agriculture and nutrition topics in Asia with focus on India, but limited evidence of work on food systems innovation, processing, distribution, or broader geographic scope beyond South Asia that the call emphasizes.', 'claude-haiku-4-5-20251001', '2026-05-19 23:44:06', '2026-05-19 23:44:12'),
(12, 3, 52, 2, 62, 'Strong alignment on food security focus and developing country context, but limited overlap on innovation/technology aspects, and geographic mismatch as Middle East/Lebanon are not listed priority regions while Africa and Asia are emphasized.', 'claude-haiku-4-5-20251001', '2026-05-19 23:44:07', '2026-05-19 23:44:12'),
(13, 3, 53, 3, 35, 'Researcher has strong geographic alignment (Africa/East Africa/Kenya matches call focus) and shares innovation interest, but lacks direct expertise in food systems, agriculture, nutrition, or food security which are core to the funding call\'s mission.', 'claude-haiku-4-5-20251001', '2026-05-19 23:44:09', NULL),
(14, 3, 54, 0, 15, 'Researcher\'s focus on biodiversity and conservation in Europe/Russia has minimal overlap with the funding call\'s priority on food systems innovation, nutrition, and developing countries in Africa, Asia, and the Americas.', 'claude-haiku-4-5-20251001', '2026-05-19 23:44:10', NULL),
(15, 3, 55, 5, 78, 'Strong alignment on nutrition and food security topics in the Americas/Peru geography, but lacks demonstrated expertise in agricultural innovation, food processing, and distribution systems that are central to the funding call.', 'claude-haiku-4-5-20251001', '2026-05-19 23:44:11', '2026-05-19 23:44:12'),
(16, 7, 41, 1, 15, 'Researcher\'s focus on food systems and food security has minimal alignment with tropical forest biodiversity conservation, though both share an interest in Asia and sustainable practices.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:43', NULL),
(17, 7, 42, 0, 15, 'While the researcher works in relevant geographies (Sub-Saharan Africa overlaps with call\'s Africa focus) and has governance expertise applicable to conservation, their primary focus on food systems and water governance lacks direct alignment with tropical forest biodiversity conservation or community-based conservation practices.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:44', NULL),
(18, 7, 43, 1, 15, 'Minimal alignment: researcher\'s focus on food security and tech food systems in Asia/China does not directly address tropical forest biodiversity conservation, though food systems could tangentially relate to land-use practices if framed through agricultural sustainability in tropical contexts.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:46', NULL),
(19, 7, 44, 0, 25, 'While the researcher is geographically well-positioned in Brazil (a key tropical forest region), her research focus on climate, agriculture, and food security does not directly align with the call\'s emphasis on biodiversity conservation and community-based conservation practices, though there is potential overlap in sustainable land-use approaches.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:47', NULL),
(20, 7, 45, 1, 15, 'Researcher\'s focus on water and governance in Africa has minimal overlap with the call\'s requirement for tropical forest biodiversity conservation expertise, though both involve African contexts.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:49', NULL),
(21, 7, 46, 1, 15, 'While the researcher\'s sustainability focus and Asian geography show minimal overlap with the funding call\'s tropical forest biodiversity conservation priorities, there is insufficient topical alignment in biodiversity, conservation, or community-based practices to warrant a strong match.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:50', NULL),
(22, 7, 47, 1, 5, 'The researcher\'s focus on malaria and disease control has minimal overlap with tropical forest biodiversity conservation, and while both work in Africa, the disciplinary mismatch (public health vs. conservation biology) and lack of environmental/conservation expertise create a poor fit for this funding call.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:52', NULL),
(23, 7, 48, 4, 32, 'Researcher has relevant biodiversity and environment expertise, but geographic focus (Europe, Russia, Arctic) does not align with call requirements (Americas, Asia, Africa), and lacks demonstrated experience in tropical forests or community-based conservation approaches.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:54', NULL),
(24, 7, 49, 5, 82, 'Strong topical alignment on environment and biodiversity with geographic match in the Americas and Mexico, but lacks explicit mention of tropical forest focus, community-based conservation, and sustainable land-use practices which are central to the funding call.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:56', '2026-05-20 13:28:07'),
(25, 7, 50, 1, 15, 'Limited alignment: researcher works on gender, agriculture, and economic development in Africa, while the call focuses on tropical forest biodiversity conservation; only geographic overlap (Africa) provides minor connection.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:58', NULL),
(26, 7, 51, 1, 15, 'While the researcher is based in Asia where the funding call operates, there is minimal topical alignment as their expertise in agriculture, nutrition, and poverty does not match the biodiversity conservation and tropical forest ecosystem focus of the call.', 'claude-haiku-4-5-20251001', '2026-05-20 13:27:59', NULL),
(27, 7, 52, 0, 15, 'Researcher\'s focus on food security, governance, and resilience in the Middle East/Lebanon shows minimal overlap with the call\'s requirements for tropical forest biodiversity conservation in Americas, Asia, and Africa, with only tangential connections through environmental themes.', 'claude-haiku-4-5-20251001', '2026-05-20 13:28:01', NULL),
(28, 7, 53, 1, 15, 'David Okonkwo\'s research focus on energy, innovation, and poverty has minimal overlap with the call\'s biodiversity conservation priorities, though his East African location (Kenya) partially aligns with the geographic scope.', 'claude-haiku-4-5-20251001', '2026-05-20 13:28:03', NULL),
(29, 7, 54, 6, 15, 'While researcher shares topic expertise in biodiversity, environment, and conservation, there is a significant geographic mismatch as Elena Volkova\'s work focuses on Europe and Russia, whereas the funding call specifically targets tropical forests in the Americas, Asia, and Africa.', 'claude-haiku-4-5-20251001', '2026-05-20 13:28:05', NULL),
(30, 7, 55, 1, 15, 'While the researcher is based in Peru (matching the geography), their expertise in nutrition, food security, and poverty has minimal overlap with the funding call\'s focus on biodiversity conservation and tropical forest ecosystem protection, with no demonstrated background in conservation science or environmental management.', 'claude-haiku-4-5-20251001', '2026-05-20 13:28:07', NULL),
(31, 16, 42, 0, 35, 'Researcher\'s qualitative social science focus on innovation systems and water governance aligns with AFRI\'s agriculture systems and natural resources priorities, but significant gaps exist: no demonstrated agricultural research expertise, limited USA focus (call emphasizes USA-based research), and qualitative-only methodology may not match NIFA\'s emphasis on foundational and applied sciences requiring empirical agricultural outcomes.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:27', NULL),
(32, 16, 43, 0, 15, 'Researcher\'s focus on food security and food systems technology has some topical overlap with AFRI priorities, but significant barriers exist: researcher is a student (not an independent PI), lacks demonstrated research credentials, geographic focus is Asia/China (AFRI requires USA-based institutions), and no evidence of formal research team or institutional support needed for competitive USDA grants.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:29', NULL),
(33, 16, 44, 0, 25, 'While the researcher\'s expertise in agriculture and food security aligns with AFRI priorities, the institution is in Brazil rather than a US-based organization, and the funding is restricted to US institutions (though international collaboration is permitted, the applicant organization must be US-based), creating a fundamental eligibility barrier.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:30', NULL),
(34, 16, 45, 0, 15, 'Researcher\'s focus on water governance in Sudan/Africa has minimal alignment with AFRI\'s agricultural science priorities, and institutional location at University of Khartoum outside the USA creates a fundamental eligibility barrier as a primary applicant, though international collaboration could be permissible as a partner.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:32', NULL),
(35, 16, 46, 0, 15, 'While the researcher\'s expertise in water, energy, and sustainability aligns with AFRI priority areas (4) and (5), the fundamental mismatch is institutional eligibility—USDA NIFA AFRI requires US-based institutions as primary applicants, and the researcher is based at a Taiwan institution, though international collaboration is permitted only in supporting roles.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:35', NULL),
(36, 16, 47, 0, 15, 'Researcher\'s focus on malaria and disease in West Africa has minimal alignment with USDA agricultural research priorities, and the researcher is based at a Ghanaian institution rather than a US institution, which is a fundamental eligibility barrier for this domestically-focused funding program.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:37', NULL),
(37, 16, 48, 0, 15, 'While the researcher\'s expertise in climate, environment, and biodiversity aligns with AFRI priority area 4 (Bioenergy, Natural Resources, and Environment), the fundamental requirement that applicants be from USA institutions with international collaboration as secondary option creates a critical barrier, as the researcher is based at Moscow State University in Russia.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:39', NULL),
(38, 16, 49, 0, 25, 'While the researcher\'s expertise in environment and biodiversity aligns with AFRI\'s natural resources and environmental priority areas, the institutional location in Mexico and research focus on Latin America create a significant mismatch with the USDA NIFA program\'s requirement for USA-based institutions as primary applicants, though international collaboration is permitted.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:40', NULL),
(39, 16, 50, 0, 15, 'Researcher\'s focus on gender, agriculture, and economic development in West Africa shows some thematic overlap with AFRI priority areas (agriculture economics, rural communities), but the geographic mismatch (Africa vs. USA requirement) and lack of alignment with specific technical research areas (plant/animal health, food safety, bioenergy, natural resources) create a substantial gap.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:43', NULL),
(40, 16, 53, 0, 15, 'The researcher\'s focus on Africa/Kenya and work on energy and poverty has minimal alignment with USDA NIFA\'s US-based agricultural research priorities, though there is tangential overlap on bioenergy; institutional location outside the USA and lack of demonstrated agricultural science expertise create significant barriers to competitiveness.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:45', NULL),
(41, 16, 54, 0, 15, 'Researcher\'s biodiversity and conservation focus in Russia/Europe has minimal alignment with USDA NIFA\'s six priority areas, and institutional location outside USA creates ineligibility barriers despite thematic overlap in environmental topics.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:47', NULL),
(42, 16, 71, 0, 42, 'Researcher\'s food security and food systems technology focus aligns with AFRI priorities (food safety, nutrition, agriculture systems, technology), but MIT intern status raises concerns about independent research capacity, institution eligibility, and lack of demonstrated agricultural science expertise or US-based research infrastructure typical of AFRI recipients.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:49', NULL),
(43, 16, 73, 0, 28, 'Researcher\'s expertise in sustainable agriculture and food security aligns with AFRI priorities, but institutional location at Oxford University (UK) and geographic focus on Africa, Asia, and Europe rather than USA creates a significant eligibility barrier, as AFRI requires a USA-based institution as the primary recipient, though international collaboration is permitted.', 'claude-haiku-4-5-20251001', '2026-06-01 18:44:51', NULL),
(44, 17, 42, 0, 35, 'Researcher\'s qualitative social science expertise in agricultural innovation systems and water governance aligns with AFRI\'s Agriculture Systems and Technology priorities, but the focus on global/African contexts outside USA, lack of applied/experimental research orientation, and absence of engagement with other AFRI priority areas (plant/animal health, food safety, nutrition, bioenergy) significantly limits competitiveness for this US-focused grant.', 'claude-haiku-4-5-20251001', '2026-06-01 18:49:49', NULL),
(45, 17, 43, 0, 35, 'Researcher\'s food security and food systems technology interests align with AFRI priorities, but significant gaps exist: researcher is a student (AFRI typically requires independent researchers), geographic focus is Asia/China rather than USA, and no evidence of research independence, institutional support, or project leadership experience.', 'claude-haiku-4-5-20251001', '2026-06-01 18:49:51', NULL),
(46, 17, 44, 0, 25, 'While the researcher\'s topics (climate, agriculture, food security) align with AFRI priorities, the fundamental geographic mismatch—researcher based in Brazil/South America versus USDA requirement for USA-based institutions as primary applicants—creates a critical barrier, though international collaboration is permitted.', 'claude-haiku-4-5-20251001', '2026-06-01 18:49:53', NULL),
(47, 17, 45, 0, 15, 'Researcher\'s focus on water governance in Sudan/Africa has minimal alignment with AFRI\'s six agricultural science priorities, and the researcher\'s institution is outside the USA eligibility requirement (though international collaboration is permitted, the applicant institution must be US-based).', 'claude-haiku-4-5-20251001', '2026-06-01 18:49:54', NULL),
(48, 17, 46, 0, 15, 'While the researcher\'s expertise in water, energy, and sustainability aligns with AFRI\'s environmental and bioenergy priorities, the critical barrier is institutional eligibility—USDA NIFA AFRI funding is restricted to U.S. institutions, and the researcher is based at National Taiwan University with a geographic focus on Asia, making them ineligible despite topical relevance.', 'claude-haiku-4-5-20251001', '2026-06-01 18:49:56', NULL),
(49, 17, 47, 0, 5, 'Researcher\'s focus on malaria and disease control in Ghana does not align with AFRI\'s agricultural science priorities, and researcher\'s institution is outside the USA where AFRI funding is restricted (though international collaboration is permitted, the researcher is not US-based and their work lacks agricultural relevance).', 'claude-haiku-4-5-20251001', '2026-06-01 18:49:58', NULL),
(50, 17, 48, 0, 15, 'While the researcher\'s expertise in climate, environment, and biodiversity aligns with AFRI\'s natural resources and environmental priorities, the institutional location (Moscow State University) and geographic focus (Europe, Russia, Arctic) do not match the USA-based requirement for this USDA domestic funding program, though international collaboration is permitted.', 'claude-haiku-4-5-20251001', '2026-06-01 18:50:00', NULL),
(51, 17, 49, 0, 28, 'While the researcher\'s expertise in environment and biodiversity aligns with AFRI priority areas 4 and potentially others, the institutional location in Mexico and focus on Latin America creates a significant barrier since AFRI is a USDA program requiring US-based applicants, though international collaboration is permitted if a US institution leads.', 'claude-haiku-4-5-20251001', '2026-06-01 18:50:02', NULL),
(52, 17, 50, 0, 15, 'Researcher\'s focus on gender, agriculture, and economic development in West Africa shows thematic overlap with AFRI priority areas 6 (Agriculture Economics and Rural Communities), but the geographic mismatch (Senegal vs. USA requirement) and lack of alignment with specific AFRI technical priorities (plant/animal health, food safety, bioenergy, etc.) significantly limits eligibility.', 'claude-haiku-4-5-20251001', '2026-06-01 18:50:04', NULL),
(53, 17, 53, 0, 15, 'Researcher is based in Kenya and focuses on African contexts, while AFRI requires USA-based institutions and domestic focus; topic alignment on energy/innovation exists but geographic and institutional requirements create fundamental misalignment.', 'claude-haiku-4-5-20251001', '2026-06-01 18:50:06', NULL),
(54, 17, 54, 0, 15, 'While the researcher\'s expertise in biodiversity, environment, and conservation aligns with AFRI\'s natural resources and environment priority area, the geographic mismatch (Saint Petersburg State University in Russia vs. USA-based requirement) and lack of demonstrated focus on agricultural applications are significant barriers to competitiveness.', 'claude-haiku-4-5-20251001', '2026-06-01 18:50:08', NULL),
(55, 17, 71, 0, 45, 'The researcher\'s focus on food security and technology in food systems aligns with AFRI priority areas 3 and 5, but the MIT intern status raises concerns about eligibility requirements, the global scope exceeds the USA-focused program, and there is no evidence of agricultural science grounding or applied research in traditional USDA-relevant domains.', 'claude-haiku-4-5-20251001', '2026-06-01 18:50:10', NULL),
(56, 17, 73, 0, 28, 'While the researcher\'s expertise in sustainable agriculture, food security, and rural development aligns with several AFRI priority areas, the fundamental mismatch is institutional eligibility—AFRI requires a USA-based institution, and the researcher is affiliated with Oxford University (UK), which is a critical disqualifying factor despite relevant research topics.', 'claude-haiku-4-5-20251001', '2026-06-01 18:50:12', NULL),
(57, 18, 42, 0, 28, 'While the researcher has relevant expertise in agricultural innovation systems, there is significant misalignment on geographic scope (global/MENA vs. USA-required), methodological approach (qualitative social science vs. data infrastructure focus), and priority areas (water governance vs. farm profitability, soil health, and data repositories).', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:29', NULL),
(58, 18, 43, 0, 15, 'Poor geographic match (Asia/China vs USA), limited institutional eligibility as a student rather than established researcher, and vague research focus on food systems without specific alignment to ODF priority areas like data repositories, soil health, farm profitability, or invasive species management.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:30', NULL),
(59, 18, 44, 0, 25, 'While the researcher has relevant expertise in agriculture and food security, the geographic mismatch (Brazil vs. USA requirement) and lack of specific focus on data frameworks, repositories, or the priority areas (farm profitability, soil health, invasive species, precision nutrition) significantly limit alignment with this USDA NIFA funding call.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:32', NULL),
(60, 18, 45, 0, 5, 'Researcher\'s focus on water and governance in Africa/Middle East/Sudan has minimal overlap with USDA\'s agricultural data framework priorities, and the researcher\'s institution is located outside the eligible USA geographic scope.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:34', NULL),
(61, 18, 46, 0, 8, 'Researcher\'s sustainability focus has minimal overlap with NIFA\'s agricultural data framework priorities, and Taiwan-based affiliation does not meet the USA geographic requirement, making this a poor match despite tangential relevance through water and energy topics.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:35', NULL),
(62, 18, 47, 0, 5, 'Researcher\'s focus on malaria and disease control in Ghana has minimal alignment with USDA NIFA\'s agricultural data framework priorities, and the researcher\'s institution is ineligible as it is not a U.S.-based entity.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:37', NULL),
