(64, 18, 49, 0, 15, 'Researcher\'s geographic location (Mexico/Latin America) and institutional affiliation (Mexican university) fall outside the USA-only eligibility requirement of this USDA NIFA funding call, despite some topical alignment in innovation and environmental/biodiversity interests.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:40', NULL),
(65, 18, 50, 0, 15, 'While the researcher has relevant agricultural expertise, there is minimal alignment due to geographic mismatch (Senegal vs. USA requirement), lack of evidence addressing ODF priority areas (data repositories, soil health, farm profitability infrastructure), and the researcher\'s focus on gender and economic development rather than the specific technical and data-driven priorities of the funding call.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:42', NULL),
(66, 18, 53, 0, 5, 'Researcher\'s focus on energy and poverty in Kenya has minimal overlap with USDA\'s agricultural data framework priorities, and institution location in Africa does not meet USA geographic requirement for NIFA funding.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:44', NULL),
(67, 18, 54, 0, 5, 'Researcher\'s focus on biodiversity and conservation in Europe/Russia has minimal alignment with USDA\'s US-based agricultural data framework priorities, and researcher\'s institution is ineligible as a non-US entity.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:45', NULL),
(68, 18, 71, 0, 45, 'Researcher\'s focus on food security and food systems technology aligns with NIFA\'s food quality and innovation goals, but lacks specific expertise in data frameworks, agricultural data repositories, soil health, farm profitability, or invasive species management that are central to this funding call, and their global focus may not align with the USA-specific geographic requirement.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:47', NULL),
(69, 18, 73, 0, 35, 'While the researcher\'s expertise in soil health, sustainable agriculture, and data-driven solutions aligns with ODF priorities, their institutional affiliation at Oxford University (UK-based) and geographic focus on Africa, Asia, and developing economies significantly mismatches the USA-only funding requirement, and they lack demonstrated experience with US agricultural systems or producer cooperatives.', 'claude-haiku-4-5-20251001', '2026-06-01 18:53:49', NULL),
(70, 19, 42, 0, 5, 'Researcher\'s expertise in qualitative social science and innovation systems has minimal alignment with ROAR\'s focus on urgent pest/pathogen diagnostics, monitoring, and mitigation strategies, and their geographic focus (Sub-Saharan Africa, MENA) does not match the U.S.-centric funding priorities.', 'claude-haiku-4-5-20251001', '2026-06-01 19:00:54', NULL),
(71, 19, 43, 0, 15, 'Researcher has relevant food security interest but lacks geographic alignment (Asia/China vs. USA focus), institutional research capacity unclear as a student, and no demonstrated expertise in agricultural pests, pathogens, diagnostics, or disease mitigation that the funding prioritizes.', 'claude-haiku-4-5-20251001', '2026-06-01 19:00:56', NULL),
(72, 19, 44, 0, 15, 'While the researcher\'s expertise in agriculture and food security is relevant, the geographic mismatch (Brazil/South America vs. USA focus) and lack of demonstrated focus on pest/pathogen diagnostics, outbreak response, or biosecurity represent significant barriers to funding eligibility.', 'claude-haiku-4-5-20251001', '2026-06-01 19:00:57', NULL),
(73, 19, 45, 0, 5, 'Researcher\'s focus on water governance in Africa/Middle East has minimal alignment with FFAR\'s urgent agricultural pest/pathogen diagnostics and mitigation research in the USA, with no demonstrated expertise in the required technical areas.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:00', NULL),
(74, 19, 46, 0, 5, 'Researcher\'s focus on water, energy, and sustainability in Asia has minimal alignment with ROAR\'s requirement for urgent agricultural pest/pathogen research addressing U.S. food supply threats, and her Taiwan-based institution and geographic focus do not match the U.S.-centric funding call.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:02', NULL),
(75, 19, 47, 0, 5, 'Researcher\'s focus on malaria and human health in West Africa has minimal alignment with ROAR\'s requirement for emerging agricultural pests/pathogens threatening the U.S. food supply, with no demonstrated expertise in crop or livestock biosecurity.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:03', NULL),
(76, 19, 48, 0, 5, 'Researcher\'s focus on climate, environment, and biodiversity in Europe/Russia/Arctic regions shows minimal alignment with ROAR\'s requirement for U.S.-based agricultural pest/pathogen research addressing domestic food security threats.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:05', NULL),
(77, 19, 49, 0, 15, 'Researcher\'s focus on environment and biodiversity in Mexico/Latin America has minimal alignment with FFAR\'s requirement for urgent research on U.S. food supply threats, though international applicants are eligible only if posing direct significant threats to the U.S., which is not demonstrated here.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:06', NULL),
(78, 19, 50, 0, 5, 'Researcher\'s focus on gender and economic development in West African agriculture does not align with ROAR\'s urgent mandate for U.S. food supply threats, pest/pathogen diagnostics, and mitigation strategies, and their institution location presents significant geographic mismatch despite international eligibility clause.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:10', NULL),
(79, 19, 53, 0, 5, 'Researcher\'s focus on energy, innovation, and poverty in Africa has minimal alignment with ROAR\'s specific mandate for rapid agricultural pest/pathogen research addressing U.S. food supply threats, and institutional location in Kenya does not meet the primary geographic requirement.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:14', NULL),
(80, 19, 54, 0, 15, 'Researcher\'s focus on biodiversity and conservation in Europe/Russia has minimal overlap with ROAR\'s requirement for urgent U.S.-based agricultural pest and pathogen research, though there is tangential relevance to biosecurity topics.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:15', NULL),
(81, 19, 71, 0, 35, 'Researcher has relevant food security expertise and institutional credibility, but lacks demonstrated focus on pest/pathogen diagnostics, monitoring systems, or outbreak response needed for ROAR\'s urgent threat mitigation mission, and their global scope doesn\'t align with the program\'s U.S.-centric requirement.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:17', NULL),
(82, 19, 73, 0, 15, 'Researcher\'s focus on sustainable agriculture and smallholder farmer support in developing economies has minimal alignment with ROAR\'s urgent mandate for rapid pest/pathogen diagnostics and outbreak mitigation in the U.S. food supply, and their geographic focus (Africa, Asia) does not match the U.S. requirement.', 'claude-haiku-4-5-20251001', '2026-06-01 19:01:18', NULL);

-- --------------------------------------------------------

--
-- Table structure for table `messages`
--

CREATE TABLE `messages` (
  `id` int NOT NULL,
  `sender_email` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `sender_name` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `recipient_type` enum('network','individual') COLLATE utf8mb4_general_ci DEFAULT NULL,
  `recipient_email` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `recipient_name` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `subject` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `body` text COLLATE utf8mb4_general_ci,
  `message_type` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `funding_call_id` int DEFAULT NULL,
  `funding_call_title` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `is_read` tinyint(1) DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `thread_id` int DEFAULT NULL,
  `parent_id` int DEFAULT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  `deleted_at` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `newsletter_campaigns`
--

CREATE TABLE `newsletter_campaigns` (
  `id` int NOT NULL,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Campaign title/subject line',
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'URL-safe campaign identifier',
  `content_html` longtext COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'HTML email content',
  `status` enum('draft','scheduled','sending','sent','paused') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft' COMMENT 'Campaign delivery status',
  `sender_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'FACT Hub' COMMENT 'Sender display name',
  `sender_email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'noreply@facthub.org' COMMENT 'Sender email address',
  `scheduled_at` timestamp NULL DEFAULT NULL COMMENT 'When campaign is scheduled to send',
  `sent_at` timestamp NULL DEFAULT NULL COMMENT 'When campaign actually finished sending',
  `analytics_json` json DEFAULT NULL COMMENT 'Campaign performance metrics (opens, clicks, bounces)',
  `created_by_user_id` int DEFAULT NULL COMMENT 'Admin user who created the campaign',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Stand-in structure for view `newsletter_campaign_stats`
-- (See below for the actual view)
--
CREATE TABLE `newsletter_campaign_stats` (
`id` int
,`title` varchar(255)
,`slug` varchar(255)
,`status` enum('draft','scheduled','sending','sent','paused')
,`created_at` timestamp
,`sent_at` timestamp
,`total_recipients` bigint
,`sent_count` decimal(23,0)
,`delivered_count` decimal(23,0)
,`bounced_count` decimal(23,0)
,`unsubscribed_count` decimal(23,0)
,`opened_count` bigint
,`clicked_count` bigint
,`open_rate` decimal(26,2)
,`click_through_rate` decimal(26,2)
);

-- --------------------------------------------------------

--
-- Table structure for table `newsletter_clicks`
--

CREATE TABLE `newsletter_clicks` (
  `id` int NOT NULL,
  `campaign_id` int NOT NULL COMMENT 'Reference to newsletter_campaigns',
  `subscriber_id` int NOT NULL COMMENT 'Reference to newsletter_subscribers',
  `link_url` varchar(2048) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'URL that was clicked',
  `click_count` int DEFAULT '1' COMMENT 'Number of times this subscriber clicked this link',
  `last_clicked_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Most recent click time',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Table structure for table `newsletter_events`
--

CREATE TABLE `newsletter_events` (
  `id` int NOT NULL,
  `recipient_id` int NOT NULL COMMENT 'Reference to newsletter_recipients',
  `event_type` enum('sent','delivered','opened','clicked','bounced','complained','unsubscribed') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Type of email event',
  `metadata_json` json DEFAULT NULL COMMENT 'Event metadata: {"link_url": "...", "user_agent": "...", "ip_address": "..."}',
  `timestamp` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'When event occurred',
