--
-- Structure for view `newsletter_campaign_stats`
--
DROP TABLE IF EXISTS `newsletter_campaign_stats`;

CREATE ALGORITHM=UNDEFINED DEFINER=`fact_user`@`localhost` SQL SECURITY DEFINER VIEW `newsletter_campaign_stats`  AS SELECT `c`.`id` AS `id`, `c`.`title` AS `title`, `c`.`slug` AS `slug`, `c`.`status` AS `status`, `c`.`created_at` AS `created_at`, `c`.`sent_at` AS `sent_at`, count(distinct `r`.`id`) AS `total_recipients`, sum((case when (`r`.`status` = 'sent') then 1 else 0 end)) AS `sent_count`, sum((case when (`r`.`status` = 'delivered') then 1 else 0 end)) AS `delivered_count`, sum((case when (`r`.`status` = 'bounced') then 1 else 0 end)) AS `bounced_count`, sum((case when (`r`.`status` = 'unsubscribed') then 1 else 0 end)) AS `unsubscribed_count`, count(distinct (case when (`e`.`event_type` = 'opened') then `e`.`recipient_id` end)) AS `opened_count`, count(distinct (case when (`e`.`event_type` = 'clicked') then `e`.`recipient_id` end)) AS `clicked_count`, round(((count(distinct (case when (`e`.`event_type` = 'opened') then `e`.`recipient_id` end)) / nullif(sum((case when (`r`.`status` in ('sent','delivered')) then 1 else 0 end)),0)) * 100),2) AS `open_rate`, round(((count(distinct (case when (`e`.`event_type` = 'clicked') then `e`.`recipient_id` end)) / nullif(count(distinct (case when (`e`.`event_type` = 'opened') then `e`.`recipient_id` end)),0)) * 100),2) AS `click_through_rate` FROM ((`newsletter_campaigns` `c` left join `newsletter_recipients` `r` on((`c`.`id` = `r`.`campaign_id`))) left join `newsletter_events` `e` on((`r`.`id` = `e`.`recipient_id`))) GROUP BY `c`.`id`, `c`.`title`, `c`.`slug`, `c`.`status`, `c`.`created_at`, `c`.`sent_at` ;

