--
-- Structure for view `newsletter_subscribers_by_segment`
--
DROP TABLE IF EXISTS `newsletter_subscribers_by_segment`;

CREATE ALGORITHM=UNDEFINED DEFINER=`fact_user`@`localhost` SQL SECURITY DEFINER VIEW `newsletter_subscribers_by_segment`  AS SELECT `ns`.`id` AS `id`, `ns`.`email` AS `email`, `ns`.`status` AS `status`, `ns`.`subscribed_at` AS `subscribed_at`, `np`.`frequency` AS `frequency`, `np`.`categories_json` AS `categories_json`, `np`.`geography_json` AS `geography_json`, `np`.`interests_json` AS `interests_json`, `np`.`research_roles_json` AS `research_roles_json`, count(distinct `ne`.`id`) AS `total_interactions`, max(`ne`.`timestamp`) AS `last_interaction_date` FROM (((`newsletter_subscribers` `ns` left join `newsletter_preferences` `np` on((`ns`.`id` = `np`.`subscriber_id`))) left join `newsletter_recipients` `nr` on((`ns`.`id` = `nr`.`subscriber_id`))) left join `newsletter_events` `ne` on((`nr`.`id` = `ne`.`recipient_id`))) WHERE (`ns`.`status` = 'active') GROUP BY `ns`.`id`, `ns`.`email`, `ns`.`status`, `ns`.`subscribed_at`, `np`.`frequency`, `np`.`categories_json`, `np`.`geography_json`, `np`.`interests_json`, `np`.`research_roles_json` ;

